413→  const handleAnalyze = async (url: string) => {
414→    // Vérification de la limite de projets (Quota mensuel)
415→    if (user) {
416→        const limit = PLAN_LIMITS[user.plan] || 1;
417→        let hostname = url;
418→        try { hostname = new URL(url).hostname; } catch(e) {}
419→
420→        // On vérifie si c'est un projet déjà existant dans l'historique global
421→        const isExistingProject = history.some(h => {
422→            try { return new URL(h.url).hostname === hostname; } 
423→            catch(e) { return false; }
424→        });
425→
426→        // Si c'est un tout nouveau projet et qu'on a atteint la limite MENSUELLE
427→        // Les anciens projets ne comptent pas dans cette limite
428→        if (!isExistingProject && monthlyProjectCount >= limit) {
429→            // Redirection vers l'onglet Abonnement
