497→    const timestamp = new Date().toISOString();
498→    const solutionWithMeta = { ...solution, timestamp };

498→    const solutionWithMeta = { ...solution, timestamp };
499→
500→    setAnalysisData(prev => {
501→        if (!prev || prev.timestamp !== analysisId) return prev;
502→        
503→        return {
504→            ...prev,
505→            generatedSolutions: {
506→                ...(prev.generatedSolutions || {}),
